import asyncio
from typing import List, Callable, Any

class AsyncPipeline:
    def __init__(self):
        self.stages: List[Callable] = []

    def add_stage(self, fn: Callable) -> "AsyncPipeline":
        self.stages.append(fn)
        return self

    async def run(self, items: List[Any]) -> List[Any]:
        results = []
        for item in items:
            value = item
            for stage in self.stages:
                if asyncio.iscoroutinefunction(stage):
                    # Await async stages sequentially for each item
                    value = await stage(value)
                else:
                    # Run sync stages sequentially for each item
                    value = stage(value)
            results.append(value)
        return results

    async def run_parallel(self, items: List[Any]) -> List[Any]:
        tasks = [self._process(item) for item in items]
        # asyncio.gather runs all tasks concurrently and awaits their collected results
        return await asyncio.gather(*tasks)

    async def _process(self, item: Any) -> Any:
        value = item
        for stage in self.stages:
            if asyncio.iscoroutinefunction(stage):
                # Crucial fix: must AWAIT the async stage to get its return value
                value = await stage(value)
            else:
                # Synchronous execution path
                value = stage(value)
        return value

